            return []
        out, q = [], deque([root])
        while q:
            level = []
            for _ in range(len(q)):
                n = q.popleft()
                level.append(n.val)
                if n.left:
                    q.append(n.left)
                if n.right:
                    q.append(n.right)
            out.append(level)
        return out

class Solution:
    def levelOrder(self, root) -> list[list[int]]:
        out: list[list[int]] = []

        def dfs(n, d):
            if not n:
                return
            if d == len(out):
                out.append([])
            out[d].append(n.val)
            dfs(n.left, d + 1)
            dfs(n.right, d + 1)

        dfs(root, 0)
        return out

